import{_ as n,o as t,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"68. Absences On Defence Service","description":"","frontmatter":{"title":"68. Absences On Defence Service","eba":"Biomedical Engineers 2025-2028","topics":["leave","employment"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/68-absences-on-defence-service.md","filePath":"ebas/biomedical-engineers/leave/68-absences-on-defence-service.md"}'),s={name:"ebas/biomedical-engineers/leave/68-absences-on-defence-service.md"};function r(i,e,c,d,l,p){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_68-absences-on-defence-service" tabindex="-1">68. Absences On Defence Service <a class="header-anchor" href="#_68-absences-on-defence-service" aria-label="Permalink to &quot;68. Absences On Defence Service&quot;">​</a></h1><p>This clause does not apply to casual Employees.</p><p><strong>68.1</strong> An Employee absent on defence service will be reimbursed by the Employer an amount equal to the difference between:</p><p><strong>(a)</strong> the amount paid in respect of a period during which the Employee was absent on defence service (as defined below); and</p><p><strong>(b)</strong> the amount the Employee could reasonably have received from the Employer as earnings for that period had the Employee not been absent on defence service.</p><p><strong>68.2</strong> An Employee will notify the Employer as soon as possible of the date they require leave for defence service. The Employee will give the Employer proof that the absence relates to defence service, the duration of such absence and the amount received for the relevant defence service period.</p><p><strong>68.3</strong> In this clause &#39;absence [or absent] on defence service&#39; has the meaning contained in section 24A of the Defence Reserve Service (Protection) Act 2001 (Cth), as amended from time to time.</p><p>Example: The Employee is on Defence Service leave for the duration of a particular pay period. Were the Employee not on Defence Service leave in that pay period they would have worked on the Sunday and Monday evening shift of each week of the pay period. The Employee is entitled to payment as though at work for each of the Sunday and Monday evening shifts less the amount of payment (not including reimbursements) from the Defence Service for the equivalent time of the Sunday and Monday evening shifts.</p>',8)])])}const m=n(s,[["render",r]]);export{f as __pageData,m as default};
